// --- 1. CÁC HÀM HELPER ---
function uuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

function clean(str) {
  if (!str) return "";
  if (Array.isArray(str)) return str.join(", "); 

  return String(str)
    .replace(/[“”‘’]/g, '"')
    .replace(/'/g, "''")
    .replace(/[\u0000-\u0019]+/g, " ")
    .replace(/[\u{1F600}-\u{1F6FF}]/gu, "") 
    .trim();
}

// Hàm format text có gắn Tên Ứng Viên (Context)
function formatTextForQdrant(str, candidateName) {
  const context = `Candidate: ${candidateName}. Content: `;
  return context + clean(str)
    .replace(/\r\n/g, "\n")
    .replace(/\n/g, "\\n\\n");
}

// --- 2. XỬ LÝ DATA ---
const items = $input.all();
const out = [];

for (const item of items) {
  const inputJson = item.json;
  let data = {};

  // --- A. Parse JSON ---
  if (inputJson.parsed_json) {
      data = inputJson.parsed_json;
  } else if (inputJson.contact_info && (inputJson.skills || inputJson.experience)) {
    data = inputJson;
  } else {
    const rawContent = inputJson.output || (inputJson.message && inputJson.message.content) || inputJson.text || JSON.stringify(inputJson);
    const jsonString = String(rawContent).replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/, '').trim();
    try {
      data = JSON.parse(jsonString);
    } catch (e) {
      const match = jsonString.match(/\{[\s\S]*\}/);
      if (match) { try { data = JSON.parse(match[0]); } catch (err) {} }
      if (!data.contact_info) {
        out.push({ json: { error: "JSON Parse Error", raw: rawContent } });
        continue; 
      }
    }
  }

  // --- B. METADATA ---
  const candidateId = uuid(); 
  const timestamp = new Date().toISOString();
  const contact = data.contact_info || {};
  const cvLink = Array.isArray(data.link_cv) ? data.link_cv[0] : data.link_cv;
  const candidateName = clean(contact.name || 'Unknown');

  const baseMetadata = {
    candidate_id: candidateId,
    candidate_name: candidateName,
    candidate_email: clean(contact.email),
    candidate_phone: clean(contact.phone),
    link_cv: clean(cvLink), 
    imported_at: timestamp
  };

  // --- C. TẠO VECTOR PAYLOAD (CHUNKING) ---

  // 1. SKILLS
  if (data.skills && Array.isArray(data.skills)) {
    data.skills.forEach((skill) => {
      if (!skill || skill.length < 2) return;
      const rawText = `Skill: ${skill}`;
      const formattedText = formatTextForQdrant(rawText, candidateName);

      out.push({
        json: {
          id: uuid(),
          text: formattedText,
          payload: { 
            ...baseMetadata, 
            key: 'skill',
            type: 'skill', 
            text: formattedText 
          }
        }
      });
    });
  }

  // 2. EXPERIENCE
  if (data.experience && Array.isArray(data.experience)) {
    data.experience.forEach((exp) => {
      const desc = exp.description || "";
      const sentences = desc.split(/(?:\. |\.\n|\n+)/).map(s => s.trim()).filter(s => s.length > 5);

      if (sentences.length > 0) {
        sentences.forEach((sentence) => {
           const rawText = `Work Experience: ${exp.role} at ${exp.company} (${exp.time || 'N/A'}). Detail: ${sentence}.`;
           const formattedText = formatTextForQdrant(rawText, candidateName);

           out.push({
             json: {
               id: uuid(),
               text: formattedText,
               payload: {
                 ...baseMetadata,
                 key: 'experience',
                 type: 'experience',
                 company: exp.company,
                 role: exp.role,
                 text: formattedText
               }
             }
           });
        });
      } else {
        const rawText = `Work Experience: ${exp.role} at ${exp.company} (${exp.time || 'N/A'}).`;
        const formattedText = formatTextForQdrant(rawText, candidateName);

        out.push({
          json: {
            id: uuid(),
            text: formattedText,
            payload: {
              ...baseMetadata,
              key: 'experience',
              type: 'experience',
              company: exp.company,
              role: exp.role,
              text: formattedText
            }
          }
        });
      }
    });
  }

  // --- 3. PROJECTS (CẬP NHẬT: TÁCH CÂU DESCRIPTION) ---
  if (data.projects && Array.isArray(data.projects)) {
    data.projects.forEach((proj) => {
      // Chuẩn bị dữ liệu chung
      const techStack = (proj.technologies && Array.isArray(proj.technologies)) 
          ? proj.technologies.join(", ") 
          : "";
      const desc = proj.description || "";

      // Logic tách câu (tương tự Experience)
      const sentences = desc.split(/(?:\. |\.\n|\n+)/).map(s => s.trim()).filter(s => s.length > 5);

      if (sentences.length > 0) {
        // TRƯỜNG HỢP 1: Mô tả dài -> Tách thành nhiều vector con
        sentences.forEach((sentence) => {
           // Mỗi vector con vẫn giữ Context: Tên dự án + Vai trò + Tech Stack + Chi tiết câu đó
           const rawText = `Project: ${proj.name} (${proj.time || 'N/A'}). Role: ${proj.role || 'Member'}. Tech Stack: ${techStack}. Detail: ${sentence}.`;
           const formattedText = formatTextForQdrant(rawText, candidateName);

           out.push({
            json: {
              id: uuid(),
              text: formattedText,
              payload: {
                ...baseMetadata,
                key: 'project',
                type: 'project',
                project_name: proj.name,
                role: proj.role,
                technologies: techStack,
                link_project: proj.link || "",
                text: formattedText
              }
            }
          });
        });
      } else {
        // TRƯỜNG HỢP 2: Mô tả quá ngắn hoặc rỗng -> Tạo 1 vector duy nhất
        const rawText = `Project: ${proj.name} (${proj.time || 'N/A'}). Role: ${proj.role || 'Member'}. Tech Stack: ${techStack}. Description: ${desc}`;
        const formattedText = formatTextForQdrant(rawText, candidateName);

        out.push({
          json: {
            id: uuid(),
            text: formattedText,
            payload: {
              ...baseMetadata,
              key: 'project',
              type: 'project',
              project_name: proj.name,
              role: proj.role,
              technologies: techStack,
              link_project: proj.link || "",
              text: formattedText
            }
          }
        });
      }
    });
  }

  // 4. EDUCATION
  if (data.education && Array.isArray(data.education)) {
    data.education.forEach((edu) => {
      const rawText = `Education: ${edu.major} at ${edu.school} (${edu.time || 'N/A'}).`;
      const formattedText = formatTextForQdrant(rawText, candidateName);

      out.push({
        json: {
          id: uuid(),
          text: formattedText,
          payload: { 
            ...baseMetadata, 
            key: 'education',
            type: 'education', 
            school: edu.school, 
            text: formattedText 
          }
        }
      });
    });
  }

  // 5. CERTIFICATION
  if (data.certification && Array.isArray(data.certification)) {
    data.certification.forEach((cert) => {
      const rawText = `Certification: ${cert.name} by ${cert.issuer || 'Unknown'} (${cert.time || 'N/A'}).`;
      const formattedText = formatTextForQdrant(rawText, candidateName);

      out.push({
        json: {
          id: uuid(),
          text: formattedText,
          payload: { 
            ...baseMetadata, 
            key: 'certification',
            type: 'certification', 
            text: formattedText 
          }
        }
      });
    });
  }

  // 6. SUMMARY
  if (data.summary) {
    const rawText = `Candidate Summary: ${data.summary}`;
    const formattedText = formatTextForQdrant(rawText, candidateName);
    out.push({
      json: {
        id: uuid(),
        text: formattedText,
        payload: { 
          ...baseMetadata, 
          key: 'summary',
          type: 'summary', 
          text: formattedText 
        }
      }
    });
  }
}

if (out.length === 0) return [{ json: { warning: "No valid vectors created." } }];
return out;

// Lấy data từ 2 node trước
const fmtItems = $items('Fn_Format');          // Node chứa text + payload
const embItems = $items('OpenAI Embedding');   // Node chứa vector

const points = [];

// Dùng Math.min để an toàn
const count = Math.min(fmtItems.length, embItems.length);

for (let i = 0; i < count; i++) {
  const f = fmtItems[i].json; // Data gốc
  const e = embItems[i].json; // Vector

  // 1. TÌM VECTOR (Logic bắt lỗi vector như cũ)
  const vector = e.embedding 
              || (e.data && e.data[0] ? e.data[0].embedding : null)
              || e.vector; 

  if (vector) {
     // Lấy dữ liệu từ payload hoặc metadata
     const sourceData = f.payload || f.metadata || {}; 

     // 2. TẠO PAYLOAD
     // Copy toàn bộ dữ liệu gốc (candidate_id, candidate_name, type...)
     const payload = { ...sourceData };

     // 3. XỬ LÝ LÀM SẠCH (Loại bỏ trường thừa)
     // Xóa các trường ngắn nếu chúng vô tình tồn tại
     delete payload.name;
     delete payload.email;
     delete payload.phone;
     delete payload.text_content; 

     // 4. ĐẢM BẢO CÁC TRƯỜNG QUAN TRỌNG
     // Đảm bảo link_cv luôn tồn tại (nếu null thì thành chuỗi rỗng)
     payload.link_cv = sourceData.link_cv || "";

     // Đảm bảo trường 'text' tồn tại (đây là nội dung chính để RAG đọc)
     // Nếu node trước trả về 'text' thì giữ nguyên, nếu không thì lấy từ f.text
     payload.text = sourceData.text || f.text || "";

     points.push({
       id: f.id,       // UUID
       vector: vector, // Vector Array
       payload: payload
     });
  }
}

// Kiểm tra debug
if (points.length === 0) {
  return [{
    json: {
      error: "Không tìm thấy Vector nào.",
      debug_check: {
        has_payload: !!fmtItems[0].json.payload
      }
    }
  }];
}

// Trả về format chuẩn
return [
  {
    json: { points }
  }
];

